  const fullRange = (): number[] =>
    Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (field === "*") return fullRange();

  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangeOrStar, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}" for ${fieldName}`);

    let start = min;
    let end = max;

