  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function validateRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Invalid value ${value} in ${context}: must be an integer between ${min} and ${max}`
    );
  }
}

function parseField(raw: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  if (raw.includes(",")) {
    const parts = raw.split(",");
    if (parts.some((p) => p.trim() === "")) {
      throw new SyntaxError(`Trailing or consecutive commas in field "${fieldName}": "${raw}"`);
    }
    const values = parts.flatMap((part) => parseField(part.trim(), config, fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (raw === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  if (raw.startsWith("*/")) {
    const stepStr = raw.slice(2);
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${raw}" for field "${fieldName}"`);
    }
    if (step > max - min) {
      throw new RangeError(
        `Step value ${step} in "${raw}" exceeds field range [${min}-${max}] for "${fieldName}"`
      );
    }
    const values: number[] = [];
    for (let v = min; v <= max; v += step) {
      values.push(v);
    }
    return values;
  }

  if (raw.includes("-")) {
    const dashIndex = raw.indexOf("-");
    if (dashIndex === 0 || dashIndex === raw.length - 1) {
      throw new SyntaxError(`Malformed range "${raw}" in field "${fieldName}"`);
    }
    const startStr = raw.slice(0, dashIndex);
    const endStr = raw.slice(dashIndex + 1);

    if (endStr.includes("-")) {
      throw new SyntaxError(`Multiple hyphens in range "${raw}" for field "${fieldName}"`);
    }

    const start = Number(startStr);
    const end = Number(endStr);

    if (!Number.isFinite(start) || !Number.isFinite(end)) {
      throw new SyntaxError(`Non-numeric range bounds in "${raw}" for field "${fieldName}"`);
    }

    validateRange(start, min, max, `field "${fieldName}"`);
    validateRange(end, min, max, `field "${fieldName}"`);

    if (start > end) {
      throw new RangeError(
        `Range start (${start}) exceeds end (${end}) in "${raw}" for field "${fieldName}"`
      );
    }

    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  const num = Number(raw);
  if (!Number.isFinite(num)) {
    throw new SyntaxError(`Unrecognised token "${raw}" in field "${fieldName}"`);
  }
  validateRange(num, min, max, `field "${fieldName}"`);
  return [num];
}

