      throw new SyntaxError(`Empty segment in list for field "${field}"`);
    }
    const values = parts.flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const stepStr = expr.slice(2);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || stepStr !== String(step)) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }
    if (step <= 0) {
      throw new RangeError(`Step must be positive, got ${step} for field "${field}"`);
    }
    const result: number[] = [];
    for (let v = min; v <= max; v += step) result.push(v);
    return result;
  }

  if (expr.includes("/")) {
    const [rangeStr, stepStr] = expr.split("/");
    if (!rangeStr || !stepStr) {
      throw new SyntaxError(`Malformed step expression "${expr}" for field "${field}"`);
    }
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || stepStr !== String(step)) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }
    if (step <= 0) {
      throw new RangeError(`Step must be positive, got ${step} for field "${field}"`);
    }
    const base = parseField(rangeStr, field);
    const rangeStart = base[0];
    const rangeEnd = base[base.length - 1];
    const result: number[] = [];
    for (let v = rangeStart; v <= rangeEnd; v += step) result.push(v);
    return result;
  }

  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression "${expr}" for field "${field}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || parts[0] !== String(start)) {
      throw new SyntaxError(`Non-integer range start in "${expr}" for field "${field}"`);
    }
    if (isNaN(end) || parts[1] !== String(end)) {
      throw new SyntaxError(`Non-integer range end in "${expr}" for field "${field}"`);
    }
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);
    return range(start, end);
  }

  if (expr === "*") {
    return range(min, max);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value) || expr !== String(value)) {
    throw new SyntaxError(`Invalid value "${expr}" for field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

