type CronFields = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseInteger(token: string, context: string): number {
  const n = Number(token);
  if (!Number.isInteger(n) || String(n) !== token.trim()) {
    throw new SyntaxError(`Expected integer, got "${token}" in field "${context}"`);
  }
  return n;
}

function expandRange(start: number, end: number, step: number, config: FieldConfig, context: string): number[] {
  if (step < 1) {
    throw new RangeError(`Step must be >= 1, got ${step} in field "${context}"`);
  }
  assertInRange(start, config.min, config.max, context);
  assertInRange(end, config.min, config.max, context);
  if (start > end) {
    throw new RangeError(`Range start ${start} > end ${end} in field "${context}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig, context: string): number[] {
  const trimmed = segment.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Empty segment in field "${context}"`);
  }

  // Step with wildcard: */n
  if (trimmed.startsWith("*/")) {
    const stepStr = trimmed.slice(2);
    const step = parseInteger(stepStr, context);
    return expandRange(config.min, config.max, step, config, context);
  }

  // Range with optional step: n-m or n-m/s
  if (trimmed.includes("-")) {
    const slashIdx = trimmed.indexOf("/");
    let rangePart: string;
    let step = 1;
    if (slashIdx !== -1) {
      rangePart = trimmed.slice(0, slashIdx);
      step = parseInteger(trimmed.slice(slashIdx + 1), context);
    } else {
      rangePart = trimmed;
    }
    const dashIdx = rangePart.indexOf("-");
    const start = parseInteger(rangePart.slice(0, dashIdx), context);
    const end = parseInteger(rangePart.slice(dashIdx + 1), context);
    return expandRange(start, end, step, config, context);
  }

  // Step on a number: n/s (non-standard but defensively handled)
  if (trimmed.includes("/")) {
    const [baseStr, stepStr] = trimmed.split("/");
    const base = parseInteger(baseStr, context);
    const step = parseInteger(stepStr, context);
    assertInRange(base, config.min, config.max, context);
    return expandRange(base, config.max, step, config, context);
  }

  // Wildcard: *
  if (trimmed === "*") {
    return expandRange(config.min, config.max, 1, config, context);
  }

  // Plain integer
  const value = parseInteger(trimmed, context);
  assertInRange(value, config.min, config.max, context);
  return [value];
}

function parseField(field: string, config: FieldConfig, name: string): number[] {
  if (field.trim() === "") {
    throw new SyntaxError(`Empty field "${name}"`);
  }

  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const expanded = parseSegment(segment, config, name);
    for (const v of expanded) {
      values.add(v);
    }
  }

  const sorted = Array.from(values).sort((a, b) => a - b);

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (name === "dayOfWeek") {
    const normalized = new Set(sorted.map((v) => (v === 7 ? 0 : v)));
    return Array.from(normalized).sort((a, b) => a - b);
  }

  return sorted;
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected string expression, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < 5; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[i], name);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
