export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

function expandRange(start: number, end: number, step: number, config: FieldConfig): number[] {
  if (start < config.min || start > config.max) {
    throw new RangeError(`Value ${start} out of range [${config.min}, ${config.max}]`);
  }
  if (end < config.min || end > config.max) {
    throw new RangeError(`Value ${end} out of range [${config.min}, ${config.max}]`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} is greater than end ${end}`);
  }
  if (step < 1) {
    throw new RangeError(`Step value must be >= 1, got ${step}`);
  }

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  // Step on wildcard: */n
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    return expandRange(config.min, config.max, step, config);
  }

  // Pure wildcard
  if (segment === "*") {
    return expandRange(config.min, config.max, 1, config);
  }

  // Range with optional step: n-m or n-m/s
  const rangeStepMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeStepMatch) {
    const start = parseInt(rangeStepMatch[1], 10);
    const end = parseInt(rangeStepMatch[2], 10);
    const step = rangeStepMatch[3] !== undefined ? parseInt(rangeStepMatch[3], 10) : 1;
    return expandRange(start, end, step, config);
  }

  // Single value with optional step: n/s (step from n to max)
  const valueStepMatch = segment.match(/^(\d+)\/(\d+)$/);
  if (valueStepMatch) {
    const start = parseInt(valueStepMatch[1], 10);
    const step = parseInt(valueStepMatch[2], 10);
    return expandRange(start, config.max, step, config);
  }

  // Plain number
  if (/^\d+$/.test(segment)) {
    const value = parseInt(segment, 10);
    if (value < config.min || value > config.max) {
      throw new RangeError(`Value ${value} out of range [${config.min}, ${config.max}]`);
    }
    return [value];
  }

  throw new SyntaxError(`Unrecognized cron field segment: "${segment}"`);
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new SyntaxError("Empty cron field");
  }

  const segments = field.split(",");
  const valueSet = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in cron field: "${field}"`);
    }
    for (const v of parseSegment(trimmed, config)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  return {
    minute: parseField(minuteField, FIELD_CONFIGS[0]),
    hour: parseField(hourField, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domField, FIELD_CONFIGS[2]),
    month: parseField(monthField, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dowField, FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

export default function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

