}

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function rangeArray(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function validateValue(value: number, field: FieldName): number {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
  return value;
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (segment === "*") {
    return rangeArray(min, max);
  }

  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${field}"`);
    }
    return rangeArray(min, max, step);
  }

  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" for field "${field}"`);
    }
    const [start, end] = parts.map(p => {
      const n = parseInt(p, 10);
      if (isNaN(n)) throw new SyntaxError(`Invalid number "${p}" in range for field "${field}"`);
      return n;
    });
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in field "${field}"`);
    }
    validateValue(start, field);
    validateValue(end, field);
    return rangeArray(start, end);
  }

  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in "${segment}" for field "${field}"`);
    }
    if (rangePart === "*") {
      return rangeArray(min, max, step);
    }
    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range in "${segment}" for field "${field}"`);
      }
      validateValue(start, field);
      validateValue(end, field);
      return rangeArray(start, end, step);
    }
  }

  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  }

  // Normalize dayOfWeek: 7 is also Sunday (0)
  const normalized = field === "dayOfWeek" && num === 7 ? 0 : num;
  validateValue(normalized, field);
  return [normalized];
}

function parseField(expression: string, field: FieldName): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) {
      throw new SyntaxError(`Empty segment in "${expression}" for field "${field}"`);
    }
    for (const v of parseSegment(trimmed, field)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
